import"./default-wbEufGYc.js";class h{constructor(){this.fish=document.querySelector("#fish"),this.fishContainer=document.querySelector("#fish-container"),this.init()}init(){this.placeFish(),window.addEventListener("resize",()=>{this.placeFish()})}placeFish(){const t=this.fishContainer.offsetWidth,s=this.fishContainer.offsetHeight,e=this.fishContainer.offsetLeft+t/2,i=this.fishContainer.offsetTop+s/2,n=i/window.innerHeight*100;this.fish.style.setProperty("--fish-size",t+"px"),this.fish.style.setProperty("--screen-size",window.innerWidth+"px"),this.fish.style.setProperty("--fish-x",e+"px"),this.fish.style.setProperty("--fish-y",i+"px"),this.fish.style.setProperty("--mask-y",n+"%")}}new h;
